            <h4>Price Range</h4>
            <div class="price-inputs">
                <input type="number" placeholder="Min" @bind="minPrice" step="0.01" min="0" />
                <span>–</span>
                <input type="number" placeholder="Max" @bind="maxPrice" step="0.01" min="0" />
            </div>
        </div>

        <div class="filter-section">
            <label class="filter-checkbox">
                <input type="checkbox" @bind="inStockOnly" />
                In Stock Only
            </label>
