@code {
    [Parameter]
    public EventCallback<Product> OnProductClicked { get; set; }

    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string currentSort = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? searchResult;
    private bool isLoading;
    private string? errorMessage;

    private int TotalPages => searchResult is null || searchResult.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)searchResult.TotalCount / searchResult.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategories();
        await LoadProducts();
    }

    private async Task LoadCategories()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load categories: {ex.Message}";
        }
    }

    private async Task LoadProducts()
    {
        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            searchResult = await ProductService.SearchAsync(filter, currentSort, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
            searchResult = null;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await LoadProducts();
    }

    private async Task GoToPage(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private async Task PreviousPage()
    {
        if (currentPage > 1)
        {
            currentPage--;
            await LoadProducts();
        }
    }

    private async Task NextPage()
    {
        if (currentPage < TotalPages)
        {
            currentPage++;
            await LoadProducts();
        }
    }

    private async Task OnProductSelected(Product product)
    {
        if (OnProductClicked.HasDelegate)
        {
            await OnProductClicked.InvokeAsync(product);
        }
    }

    private void AddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

